1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Grid } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill single live cell (underpopulation)", () => {
9	    // Grid: 3x3, center cell (1,1) is alive, no neighbors
10	    const grid: Grid = [
11	      [false, false, false],
12	      [false, true, false],
13	      [false, false, false],
14	    ];
15	    const result = nextGeneration(grid);
16	    // Center cell should be dead - it has 0 neighbors (underpopulation)
17	    expect(result).toEqual([
18	      [false, false, false],
19	      [false, false, false],
20	      [false, false, false],
21	    ]);
22	  });
23	  it("should kill live cell with one neighbor (underpopulation)", () => {
24	    // Grid: 3x3, center cell (1,1) is alive, only cell (1,2) is alive
25	    const grid: Grid = [
26	      [false, false, false],
27	      [true, true, false],
28	      [false, false, false],
29	    ];
30	    const result = nextGeneration(grid);
31	    // Both cells should be dead - center has 1 neighbor (underpopulation)
32	    expect(result).toEqual([
33	      [false, false, false],
34	      [false, false, false],
35	      [false, false, false],
36	    ]);
37	  });
38	  it("should keep live cell alive with 2 neighbors (survival)", () => {
39	    // Grid: 3x3, center cell (1,1) is alive with 2 neighbors
40	    const grid: Grid = [
41	      [false, false, false],
42	      [true, true, true],
43	      [false, false, false],
44	    ];
45	    const result = nextGeneration(grid);
46	    // Center cell should stay alive (2 neighbors = survival)
47	    expect(result).toEqual([
48	      [false, true, false],
49	      [false, true, false],
50	      [false, true, false],
51	    ]);
52	  });
53	  it("should keep live cell with three neighbors (survival)", () => {
54	    // Grid: 3x3, center cell (1,1) is alive with 3 neighbors
55	    const grid: Grid = [
56	      [false, true, false],
57	      [true, true, false],
58	      [false, false, false],
59	    ];
60	    const result = nextGeneration(grid);
61	    // Center cell should stay alive (3 neighbors = survival)
62	    expect(result).toEqual([
63	      [false, true, false],
64	      [true, true, false],
65	      [false, false, false],
66	    ]);
67	  });
68	  it("should kill live cell with four neighbors (overpopulation)", () => {
69	    // Grid: 3x3, center cell (1,1) is alive with 4 neighbors
70	    const grid: Grid = [
71	      [true, false, true],
72	      [true, true, false],
73	      [false, false, false],
74	    ];
75	    const result = nextGeneration(grid);
76	    // Center cell should be dead (4 neighbors = overpopulation)
77	    expect(result).toEqual([
78	      [true, false, true],
79	      [true, false, false],
80	      [false, false, false],
81	    ]);
82	  });
83	  it("should revive dead cell with exactly 3 neighbors (reproduction)", () => {
84	    // Grid: 3x3, center cell (1,1) is dead with 3 neighbors
85	    const grid: Grid = [
86	      [false, true, false],
87	      [true, false, true],
88	      [false, false, false],
89	    ];
90	    const result = nextGeneration(grid);
91	    // Center cell should be alive (dead cell with 3 neighbors = reproduction)
92	    expect(result).toEqual([
93	      [false, true, false],
94	      [true, true, true],
95	      [false, false, false],
96	    ]);
97	  });
98	  it("should not revive dead cell with two neighbors", () => {
99	    // Grid: 3x3, center cell (1,1) is dead with 2 neighbors
100	    const grid: Grid = [
101	      [false, false, false],
102	      [true, false, true],
103	      [false, false, false],
104	    ];
105	    const result = nextGeneration(grid);
106	    // Center cell should stay dead (dead cell with 2 neighbors = no reproduction)
107	    expect(result).toEqual([
108	      [false, false, false],
109	      [false, false, false],
110	      [false, false, false],
111	    ]);
112	  });
113	  it("should not revive dead cell with four neighbors", () => {
114	    // Grid: 5x5, center cell (2,2) is dead with exactly 4 neighbors
115	    // Only the 4 corner neighbors of center are alive, all others dead
116	    const grid: Grid = [
117	      [false, false, false, false, false],
118	      [false, true, false, true, false],
119	      [false, false, false, false, false],
120	      [false, true, false, true, false],
121	      [false, false, false, false, false],
122	    ];
123	    const result = nextGeneration(grid);
124	    // Center cell (2,2) should stay dead (dead cell with 4 neighbors = no reproduction)
125	    // The 4 neighbors each have 2 neighbors (not 2 or 3 alive neighbors for survival)
126	    // so they should all die too
127	    expect(result).toEqual([
128	      [false, false, false, false, false],
129	      [false, false, false, false, false],
130	      [false, false, false, false, false],
131	      [false, false, false, false, false],
132	      [false, false, false, false, false],
133	    ]);
134	  });
135	  it.todo("should apply rules to multiple cells simultaneously");
136	  it.todo("should work with negative coordinates");
137	  it.todo("should handle blinker pattern oscillation");
138	  it.todo("should handle block pattern persistence");
139	});
